var CONVERSATIONS_NL_FR = [
{ title: "Koffie bestellen in Parijs", scene: "Je zit op een klein terras in Parijs vlak bij de Seine. De ober komt naar je tafel en je wilt eenvoudig maar beleefd bestellen.", lines: [{ who: "them", fr: "Bonjour, vous désirez ?", nl: "Goedendag, wat wenst u?" }, { who: "you", fr: "Bonjour, je voudrais un café, s’il vous plaît.", nl: "Goedendag, ik wil graag een koffie, alstublieft." }, { who: "them", fr: "Très bien, un café.", nl: "Heel goed, een koffie." }, { who: "you", fr: "Et un verre d’eau, s’il vous plaît.", nl: "En een glas water, alstublieft." }, { who: "them", fr: "Bien sûr, avec plaisir.", nl: "Natuurlijk, met plezier." }, { who: "you", fr: "Je peux m’asseoir ici ?", nl: "Mag ik hier zitten?" }, { who: "them", fr: "Oui, cette table est libre.", nl: "Ja, deze tafel is vrij." }, { who: "you", fr: "Merci beaucoup.", nl: "Hartelijk dank." }, { who: "them", fr: "Voilà votre café et votre eau.", nl: "Hier is uw koffie en uw water." }, { who: "you", fr: "L’addition, s’il vous plaît.", nl: "De rekening, alstublieft." }, { who: "them", fr: "Ça fait quatre euros.", nl: "Dat is vier euro." }, { who: "you", fr: "Je peux payer par carte ?", nl: "Kan ik met kaart betalen?" }] },
{ title: "Inchecken in een hotel in Lyon", scene: "Je komt aan bij een hotel in Lyon na een lange treinreis. Je hebt vooraf gereserveerd en wilt weten of ontbijt inbegrepen is.", lines: [{ who: "them", fr: "Bonjour, bienvenue à l’hôtel.", nl: "Goedendag, welkom in het hotel." }, { who: "you", fr: "Bonjour, j’ai une réservation.", nl: "Goedendag, ik heb een reservering." }, { who: "them", fr: "À quel nom, s’il vous plaît ?", nl: "Op welke naam, alstublieft?" }, { who: "you", fr: "Au nom de De Vries.", nl: "Op naam van De Vries." }, { who: "them", fr: "Oui, une chambre pour deux nuits.", nl: "Ja, een kamer voor twee nachten." }, { who: "you", fr: "La chambre est prête ?", nl: "Is de kamer klaar?" }, { who: "them", fr: "Oui, elle est prête.", nl: "Ja, die is klaar." }, { who: "you", fr: "Le petit-déjeuner est inclus ?", nl: "Is het ontbijt inbegrepen?" }, { who: "them", fr: "Oui, de sept heures à dix heures.", nl: "Ja, van zeven uur tot tien uur." }, { who: "you", fr: "Où est l’ascenseur ?", nl: "Waar is de lift?" }, { who: "them", fr: "À droite, après la réception.", nl: "Rechts, na de receptie." }, { who: "you", fr: "Merci pour votre aide.", nl: "Bedankt voor uw hulp." }] },
{ title: "De weg vragen in Brussel", scene: "Je bent in Brussel en zoekt het centraal station. Je spreekt een voorbijganger beleefd aan op straat.", lines: [{ who: "you", fr: "Excusez-moi, monsieur.", nl: "Excuseert u mij, meneer." }, { who: "them", fr: "Oui, je vous écoute.", nl: "Ja, ik luister." }, { who: "you", fr: "Où est la gare centrale ?", nl: "Waar is het centraal station?" }, { who: "them", fr: "Allez tout droit, puis tournez à gauche.", nl: "Ga rechtdoor en sla daarna linksaf." }, { who: "you", fr: "C’est loin d’ici ?", nl: "Is het ver van hier?" }, { who: "them", fr: "Non, c’est à dix minutes à pied.", nl: "Nee, het is tien minuten lopen." }, { who: "you", fr: "Je dois prendre cette rue ?", nl: "Moet ik deze straat nemen?" }, { who: "them", fr: "Oui, cette rue va vers la gare.", nl: "Ja, deze straat gaat richting het station." }, { who: "you", fr: "Très bien, merci.", nl: "Heel goed, bedankt." }, { who: "them", fr: "Avec plaisir.", nl: "Graag gedaan." }, { who: "you", fr: "Bonne journée.", nl: "Fijne dag." }, { who: "them", fr: "Bonne journée à vous aussi.", nl: "U ook een fijne dag." }] },
{ title: "Dineren in Montréal", scene: "Je eet in een restaurant in Montréal en wilt iets lokaals proberen. Je vraagt de server om een aanbeveling en controleert of het gerecht pittig is.", lines: [{ who: "them", fr: "Bonsoir, vous êtes prêts à commander ?", nl: "Goedenavond, bent u klaar om te bestellen?" }, { who: "you", fr: "Oui, qu’est-ce que vous recommandez ?", nl: "Ja, wat raadt u aan?" }, { who: "them", fr: "Je recommande le plat du jour.", nl: "Ik raad het gerecht van de dag aan." }, { who: "you", fr: "C’est avec viande ou poisson ?", nl: "Is het met vlees of vis?" }, { who: "them", fr: "C’est avec poisson et légumes.", nl: "Het is met vis en groenten." }, { who: "you", fr: "Est-ce que c’est épicé ?", nl: "Is het pittig?" }, { who: "them", fr: "Non, c’est assez doux.", nl: "Nee, het is vrij mild." }, { who: "you", fr: "Très bien, je prends ça.", nl: "Heel goed, ik neem dat." }, { who: "them", fr: "Vous voulez quelque chose à boire ?", nl: "Wilt u iets drinken?" }, { who: "you", fr: "Une eau gazeuse, s’il vous plaît.", nl: "Bruisend water, alstublieft." }, { who: "them", fr: "Parfait, merci.", nl: "Perfect, bedankt." }, { who: "you", fr: "Merci beaucoup.", nl: "Hartelijk dank." }] },
{ title: "Treinkaartjes kopen in Genève", scene: "Je bent op het station in Genève en wilt met de trein naar Lausanne. Je vraagt bij het loket om een kaartje en informatie over het perron.", lines: [{ who: "them", fr: "Bonjour, je peux vous aider ?", nl: "Goedendag, kan ik u helpen?" }, { who: "you", fr: "Bonjour, je voudrais un billet pour Lausanne.", nl: "Goedendag, ik wil graag een kaartje naar Lausanne." }, { who: "them", fr: "Aller simple ou aller-retour ?", nl: "Enkele reis of retour?" }, { who: "you", fr: "Aller simple, s’il vous plaît.", nl: "Enkele reis, alstublieft." }, { who: "them", fr: "Le prochain train part à quatorze heures.", nl: "De volgende trein vertrekt om veertien uur." }, { who: "you", fr: "Il part de quel quai ?", nl: "Van welk perron vertrekt hij?" }, { who: "them", fr: "Du quai numéro trois.", nl: "Van perron nummer drie." }, { who: "you", fr: "Ça coûte combien ?", nl: "Hoeveel kost dat?" }, { who: "them", fr: "Ça coûte vingt euros.", nl: "Dat kost twintig euro." }, { who: "you", fr: "Je peux payer par carte ?", nl: "Kan ik met kaart betalen?" }, { who: "them", fr: "Oui, bien sûr.", nl: "Ja, natuurlijk." }, { who: "you", fr: "Merci, bonne journée.", nl: "Bedankt, fijne dag." }] },
{ title: "Winkelen in Nice", scene: "Je bent in een kledingwinkel in Nice en ziet een overhemd dat je mooi vindt. Je wilt het passen en vraagt om een andere maat.", lines: [{ who: "them", fr: "Bonjour, vous cherchez quelque chose ?", nl: "Goedendag, zoekt u iets?" }, { who: "you", fr: "Bonjour, j’aime cette chemise.", nl: "Goedendag, ik vind dit overhemd mooi." }, { who: "them", fr: "Très bon choix.", nl: "Zeer goede keuze." }, { who: "you", fr: "Je peux essayer ?", nl: "Mag ik passen?" }, { who: "them", fr: "Oui, les cabines sont à gauche.", nl: "Ja, de paskamers zijn links." }, { who: "you", fr: "Vous avez une autre taille ?", nl: "Heeft u een andere maat?" }, { who: "them", fr: "Oui, plus petite ou plus grande ?", nl: "Ja, kleiner of groter?" }, { who: "you", fr: "Plus grande, s’il vous plaît.", nl: "Groter, alstublieft." }, { who: "them", fr: "Voilà, essayez celle-ci.", nl: "Hier, probeer deze." }, { who: "you", fr: "Merci, cette taille est meilleure.", nl: "Bedankt, deze maat is beter." }, { who: "them", fr: "Vous voulez l’acheter ?", nl: "Wilt u het kopen?" }, { who: "you", fr: "Oui, je vais payer par carte.", nl: "Ja, ik ga met kaart betalen." }] },
{ title: "Naar de apotheek in Marseille", scene: "Je voelt je niet goed tijdens een verblijf in Marseille. Je gaat naar een apotheek en legt eenvoudig uit wat je nodig hebt.", lines: [{ who: "them", fr: "Bonjour, monsieur, je peux vous aider ?", nl: "Goedendag meneer, kan ik u helpen?" }, { who: "you", fr: "Bonjour, je suis malade.", nl: "Goedendag, ik ben ziek." }, { who: "them", fr: "Qu’est-ce que vous avez ?", nl: "Wat heeft u?" }, { who: "you", fr: "J’ai mal à la tête et au ventre.", nl: "Ik heb hoofdpijn en buikpijn." }, { who: "them", fr: "Vous avez de la fièvre ?", nl: "Heeft u koorts?" }, { who: "you", fr: "Peut-être, je ne sais pas.", nl: "Misschien, ik weet het niet." }, { who: "them", fr: "Vous êtes allergique à quelque chose ?", nl: "Bent u ergens allergisch voor?" }, { who: "you", fr: "Non, je ne suis pas allergique.", nl: "Nee, ik ben niet allergisch." }, { who: "them", fr: "Je vous conseille ce médicament.", nl: "Ik raad u dit medicijn aan." }, { who: "you", fr: "Combien ça coûte ?", nl: "Hoeveel kost dat?" }, { who: "them", fr: "Ça coûte huit euros.", nl: "Dat kost acht euro." }, { who: "you", fr: "Merci pour votre aide.", nl: "Bedankt voor uw hulp." }] },
{ title: "Smalltalk met een local in Québec", scene: "Je zit in een café in Québec en raakt aan de praat met iemand aan de tafel naast je. Je vertelt dat je uit Nederland komt en Frans leert.", lines: [{ who: "you", fr: "Bonjour, cette place est libre ?", nl: "Goedendag, is deze plek vrij?" }, { who: "them", fr: "Oui, bien sûr.", nl: "Ja, natuurlijk." }, { who: "you", fr: "Merci, je visite Québec pour quelques jours.", nl: "Bedankt, ik bezoek Québec voor een paar dagen." }, { who: "them", fr: "Ah, très bien, vous venez d’où ?", nl: "Ah, heel goed, waar komt u vandaan?" }, { who: "you", fr: "Je viens des Pays-Bas.", nl: "Ik kom uit Nederland." }, { who: "them", fr: "Vous parlez très bien français.", nl: "U spreekt heel goed Frans." }, { who: "you", fr: "Merci, j’apprends le français.", nl: "Bedankt, ik leer Frans." }, { who: "them", fr: "Vous aimez la ville ?", nl: "Vindt u de stad leuk?" }, { who: "you", fr: "Oui, j’aime beaucoup cette ville.", nl: "Ja, ik vind deze stad erg leuk." }, { who: "them", fr: "Vous avez déjà visité le vieux quartier ?", nl: "Heeft u de oude wijk al bezocht?" }, { who: "you", fr: "Pas encore, mais je veux y aller demain.", nl: "Nog niet, maar ik wil er morgen naartoe." }, { who: "them", fr: "Bonne idée, c’est très joli.", nl: "Goed idee, het is erg mooi." }] }
];
